require("dotenv").config();const DiscordNotifier=require("./services/discordNotifier"),NFTTracker=require("./services/nftTracker");async function sleep(ms){return new Promise((r=>setTimeout(r,ms)))}async function sendSingleBasePaint(notifier,tracker){const contractAddress="0x1b7902f8bfe3ff8b074e113d60f7d6f8a1dc9d46",floorPrice=await tracker.getFloorPrice(contractAddress,"Base","basepaint"),nftMeta=await tracker.getNFTMetadata(contractAddress,"232","Base"),data={type:"purchase",isBulk:!1,walletName:"TestWallet",walletAddress:"0x1234567890123456789012345678901234567890",tokenName:"BasePaint",tokenId:"232",contractAddress:contractAddress,transactionHash:"0x"+"a".repeat(64),chainName:"Base",timestamp:new Date,price:.01,priceUSD:0,quantity:1,imageUrl:nftMeta?.imageUrl||null,nftName:null,nativeSymbol:"ETH",floorPrice:floorPrice||"-"};await notifier.sendNotification(data,tracker)}async function sendBulkBasePaint(notifier,tracker){const contractAddress="0x1b7902f8bfe3ff8b074e113d60f7d6f8a1dc9d46",ids=["323","111","423","4444","123","88","881"],floorPrice=await tracker.getFloorPrice(contractAddress,"Base","basepaint"),repMeta=await tracker.getNFTMetadata(contractAddress,ids[0],"Base"),data={type:"purchase",isBulk:!0,walletName:"TestWallet",walletAddress:"0x1234567890123456789012345678901234567890",tokenName:"BasePaint",tokenId:ids[0],contractAddress:contractAddress,transactionHash:"0x"+"b".repeat(64),chainName:"Base",timestamp:new Date,totalPrice:.07,quantity:ids.length,imageUrl:repMeta?.imageUrl||null,nftName:null,nativeSymbol:"ETH",floorPrice:floorPrice||"-"};await notifier.sendNotification(data,tracker)}async function sendBulkMintBase(notifier,tracker){const data={type:"mint",isBulk:!0,walletName:"TestWallet",walletAddress:"0x1234567890123456789012345678901234567890",tokenName:"Test Mint Collection",tokenId:"1",contractAddress:"0x0000000000000000000000000000000000000000",transactionHash:"0x"+"c".repeat(64),chainName:"Base",timestamp:new Date,totalPrice:.008,quantity:4,imageUrl:null,nftName:null,nativeSymbol:"ETH",floorPrice:"-"};await notifier.sendNotification(data,tracker)}async function run(){const notifier=new DiscordNotifier,tracker=new NFTTracker;try{console.log("🔗 Connecting to Discord..."),await notifier.connect(),await new Promise((resolve=>{const start=Date.now(),timer=setInterval((()=>{(notifier.isReady||Date.now()-start>1e4)&&(clearInterval(timer),resolve())}),100)})),console.log("🧪 Scenario 1: single purchase BasePaint #232"),await sendSingleBasePaint(notifier,tracker),await sleep(600),console.log("🧪 Scenario 2: bulk purchase 7x BasePaint"),await sendBulkBasePaint(notifier,tracker),await sleep(600),console.log("🧪 Scenario 3: bulk mint 4 on Base"),await sendBulkMintBase(notifier,tracker),console.log("✅ All live scenarios dispatched")}catch(e){console.error("❌ Live scenarios failed:",e)}finally{await notifier.disconnect()}}run();